const d = $input.first().json;
let model = {};
try {
  const text = d.content[0].text;
  const clean = text.replace(/```json|```/g, '').trim();
  model = JSON.parse(clean);
} catch(e) {
  model = { error: 'Could not parse financial model', raw: d.content ? d.content[0].text : 'No response' };
}
// Merge brand data back in (it was lost after HTTP request)
const brandData = $('Phase 5 Trigger').first().json;
return [{ json: { ...brandData, financialModel: model, phase: 5, financialModelAt: new Date().toISOString() } }];

const d = $input.first().json;
let loiText = '';
try {
  loiText = d.content[0].text;
} catch(e) {
  loiText = 'LOI generation failed. Manual draft required.';
}
const brandData = $('Parse Financial Model').first().json;
return [{ json: { ...brandData, loiText, loiGeneratedAt: new Date().toISOString() } }];
